arguments.file_text:
@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_d92d2f6e3986415e8f3e4ff6368f9205.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<div class="chat-app">
    @* ── Left sidebar: channel list ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @foreach (var channel in _channels)
            {
                <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                    @onclick="() => SelectChannelAsync(channel)">
                    <div class="channel-name"># @channel.Name</div>
                    <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </li>
            }
        </ul>
    </aside>

    @* ── Main message area ── *@
    <section class="message-area @(_threadOpen ? "thread-open" : "")">
        @if (_activeChannel is not null)
        {
            <div class="message-header">
                <h2># @_activeChannel.Name</h2>
                <span class="channel-description">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="_messageListRef" @onscroll="OnMessageListScroll">
                @if (_loadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var msg in _messages)
                {
                    <div class="message-row" @onmouseenter="() => _hoveredMessageId = msg.Id"
                         @onmouseleave="() => _hoveredMessageId = null">
                        <div class="message-bubble">
                            <div class="message-meta">
                                <span class="author">@msg.Author</span>
                                <span class="timestamp">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="message-content">@msg.Content</div>

                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reaction-bar">
                                    @foreach (var reaction in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", reaction.Users)"
                                                @onclick="() => AddReactionAsync(msg.Id, reaction.Emoji)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @{ var threadSummary = _threadSummaries.GetValueOrDefault(msg.Id); }
                            @if (threadSummary is not null)
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                    💬 @threadSummary.ReplyCount @(threadSummary.ReplyCount == 1 ? "reply" : "replies")
                                    — last @FormatRelativeTime(threadSummary.LastReplyAt)
                                </button>
                            }
                        </div>

                        @if (_hoveredMessageId == msg.Id)
                        {
                            <div class="message-actions">
                                <button class="action-btn" title="Reply in thread" @onclick="() => OpenThreadAsync(msg)">
                                    💬
                                </button>
                                <button class="action-btn" title="Add reaction"
                                        @onclick="() => ToggleEmojiPicker(msg.Id)">
                                    😀
                                </button>
                            </div>

                            @if (_emojiPickerMessageId == msg.Id)
                            {
                                <div class="emoji-picker">
                                    @foreach (var emoji in _commonEmojis)
                                    {
                                        <button class="emoji-option" @onclick="() => AddReactionAsync(msg.Id, emoji)">
                                            @emoji
                                        </button>
                                    }
                                </div>
                            }
                        }
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="_newMessageText" @bind:event="oninput"
                          @onkeydown="OnMessageKeyDown"
                          placeholder="Message #@_activeChannel.Name" rows="1"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(_newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right panel: thread view ── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <span class="author">@_threadRootMessage.Author</span>
                <p>@_threadRootMessage.Content</p>
            </div>

            <div class="thread-replies">
                @foreach (var reply in _threadReplies)
                {
                    <div class="message-row">
                        <div class="message-bubble">
                            <div class="message-meta">
                                <span class="author">@reply.Author</span>
                                <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-content">@reply.Content</div>

                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reaction-bar">
                                    @foreach (var reaction in reply.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", reaction.Users)"
                                                @onclick="() => AddReactionAsync(reply.Id, reaction.Emoji)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="_threadReplyText" @bind:event="oninput"
                          @onkeydown="OnThreadReplyKeyDown"
                          placeholder="Reply…" rows="1"></textarea>
                <button class="send-btn" @onclick="SendThreadReplyAsync" disabled="@string.IsNullOrWhiteSpace(_threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private List<Channel> _channels = new();
    private List<Message> _messages = new();
    private List<Message> _threadReplies = new();
    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    private Channel? _activeChannel;
    private int? _activeChannelId;
    private Message? _threadRootMessage;
    private bool _threadOpen;

    private string _newMessageText = string.Empty;
    private string _threadReplyText = string.Empty;

    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;
    private bool _loadingMore;
    private bool _allMessagesLoaded;

    private ElementReference _messageListRef;

    private const int PageSize = 30;

    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();

        if (_channels.Count > 0)
        {
            await SelectChannelAsync(_channels[0]);
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        _activeChannel = channel;
        _activeChannelId = channel.Id;
        _allMessagesLoaded = false;
        _emojiPickerMessageId = null;

        _messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        await ChatService.MarkChannelReadAsync(channel.Id);

        BuildThreadSummaries();
        StateHasChanged();

        await ScrollToBottom();
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessageText) || _activeChannel is null)
            return;

        var sent = await ChatService.SendMessageAsync(_activeChannel.Id, _newMessageText.Trim(), null);
        _newMessageText = string.Empty;
        _messages.Add(sent);

        StateHasChanged();
        await ScrollToBottom();
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessageAsync();
        }
    }

    private async Task OnMessageListScroll()
    {
        if (_loadingMore || _allMessagesLoaded || _activeChannel is null)
            return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            await LoadOlderMessagesAsync();
        }
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (_activeChannel is null) return;

        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannel.Id, _messages.Count, PageSize);

        if (older.Count < PageSize)
            _allMessagesLoaded = true;

        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            BuildThreadSummaries();
        }

        _loadingMore = false;
    }

    private async Task OpenThreadAsync(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadReplyText = string.Empty;
        _emojiPickerMessageId = null;

        _threadReplies = await ChatService.GetThreadAsync(rootMessage.Id);
        _threadOpen = true;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies.Clear();
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _threadRootMessage is null || _activeChannel is null)
            return;

        var reply = await ChatService.SendMessageAsync(_activeChannel.Id, _threadReplyText.Trim(), _threadRootMessage.Id);
        _threadReplyText = string.Empty;
        _threadReplies.Add(reply);

        // Update thread summary in main view
        var summary = _threadSummaries.GetValueOrDefault(_threadRootMessage.Id);
        _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(
            _threadRootMessage.Id,
            (summary?.ReplyCount ?? 0) + 1,
            reply.SentAt
        );
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Refresh the message list to reflect the new reaction
        if (_activeChannel is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannel.Id, 0, _messages.Count);
        }

        if (_threadRootMessage is not null)
        {
            _threadReplies = await ChatService.GetThreadAsync(_threadRootMessage.Id);
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private void BuildThreadSummaries()
    {
        _threadSummaries.Clear();
        // Group reply messages by their root
        var replies = _messages.Where(m => m.ReplyToId is not null).ToList();
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            _threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt)
            );
        }
    }

    private async Task ScrollToBottom()
    {
        await Task.Yield();
        await JS.InvokeVoidAsync("eval", "{ const el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight; }");
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }

    private static string TruncateDescription(string desc)
    {
        return desc.Length > 50 ? desc[..47] + "…" : desc;
    }
}

