    display: flex;
    align-items: baseline;
    gap: 8px;
}

.message-meta .author {
    font-weight: 700;
    font-size: 0.95rem;
}

.message-meta .timestamp {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    margin: 2px 0 4px;
    font-size: 0.95rem;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

/* ── Reactions ── */
.reaction-bar {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    padding: 2px 8px;
    border: 1px solid #e1e1e1;
    border-radius: 12px;
    background: #f0f0f0;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #dde7fc;
    border-color: #1264a3;
}

/* ── Thread link ── */
.thread-link {
    display: inline-block;
    margin-top: 4px;
    padding: 0;
    border: none;
    background: none;
    color: #1264a3;
    font-size: 0.8rem;
    cursor: pointer;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

/* ── Hover action buttons ── */
.message-actions {
    position: absolute;
    top: -8px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0,0,0,0.1);
    z-index: 10;
}

.action-btn {
    border: none;
    background: transparent;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    font-size: 1rem;
    line-height: 1;
}

.action-btn:hover {
    background: #f0f0f0;
}

/* ── Emoji picker ── */
.emoji-picker {
    position: absolute;
    top: -8px;
    right: 80px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.15);
    z-index: 11;
}

.emoji-option {
    border: none;
    background: transparent;
    cursor: pointer;
    padding: 4px 6px;
    border-radius: 4px;
    font-size: 1.2rem;
    line-height: 1;
}

.emoji-option:hover {
    background: #f0f0f0;
}

/* ── Message input ── */
.message-input-area {
    display: flex;
    align-items: flex-end;
    gap: 8px;
    padding: 12px 20px;
    border-top: 1px solid #e1e1e1;
    background: #fff;
    flex-shrink: 0;
}

.message-input-area textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: 10px 12px;
    font-size: 0.95rem;
    font-family: inherit;
    line-height: 1.4;
    outline: none;
    transition: border-color 0.15s;
    max-height: 120px;
}

.message-input-area textarea:focus {
    border-color: #1264a3;
}

.send-btn {
    padding: 10px 20px;
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 8px;
    font-weight: 600;
    font-size: 0.9rem;
    cursor: pointer;
    transition: background 0.15s;
    white-space: nowrap;
}

.send-btn:hover:not(:disabled) {
    background: #005e44;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

