toolArgs.file_text:
/* ── Chat app root layout ── */
.chat-app {
    display: flex;
    height: 100vh;
    width: 100vw;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    color: #1d1c1d;
    background: #fff;
}

/* ── Left sidebar ── */
.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #3f0e40;
    color: #cfc3cf;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #522653;
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid #522653;
}

.sidebar-header h3 {
    margin: 0;
    color: #fff;
    font-size: 1.1rem;
    font-weight: 700;
}

.channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 6px 16px;
    cursor: pointer;
    border-radius: 6px;
    margin: 1px 8px;
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 4px;
    transition: background 0.15s;
    position: relative;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.1);
}

.channel-item.active {
    background: #1264a3;
    color: #fff;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    flex: 1;
}

.channel-desc {
    width: 100%;
    font-size: 0.75rem;
    opacity: 0.7;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

/* ── Main message area ── */
.message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
}

.message-area.thread-open {
    /* reduces to ~55% when thread panel is visible */
}

.message-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e1e1e1;
    background: #fff;
    flex-shrink: 0;
}

.message-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
}

.channel-description {
    font-size: 0.85rem;
    color: #616061;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 20px;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #888;
    font-size: 0.85rem;
}

/* ── Message row ── */
.message-row {
    position: relative;
    padding: 4px 0;
}

.message-row:hover {
    background: #f8f8f8;
    border-radius: 6px;
}

.message-bubble {
    padding: 4px 8px;
}

.message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
}

.message-meta .author {
    font-weight: 700;
    font-size: 0.95rem;
}

.message-meta .timestamp {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    margin: 2px 0 4px;
    font-size: 0.95rem;
    line-height: 1.45;
    white-space: pre-wrap;
    word-break: break-word;
}

/* ── Reactions ── */
.reaction-bar {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    padding: 2px 8px;
    border: 1px solid #e1e1e1;
    border-radius: 12px;
    background: #f0f0f0;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #dde7fc;
    border-color: #1264a3;
}

/* ── Thread link ── */
.thread-link {
    display: inline-block;
    margin-top: 4px;
    padding: 0;
    border: none;
    background: none;
    color: #1264a3;
    font-size: 0.8rem;
    cursor: pointer;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

/* ── Hover action buttons ── */
.message-actions {
    position: absolute;
    top: -8px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: #fff;
